import Navigation from '../components/Navigation';
import Dish from '../components/Dish';
import { NavLink } from 'react-router-dom';

const Menu = (props) => {

    return (
        <section>
            <main>
                <h1>Menu</h1>
                <section className="main-container">
                    <NavLink />
                </section>
            </main>
            <Navigation />
        </section>
    );
};

export default Menu;
